    27→function ensureDataDir() {
    28→  fs.mkdirSync(DATA_DIR, { recursive: true });
    29→}
    30→
    31→function readJsonArray(fileName) {
    32→  try {
    33→    const p = path.join(DATA_DIR, fileName);
    34→    if (!fs.existsSync(p)) return [];
    35→    const raw = fs.readFileSync(p, 'utf8');
    36→    const parsed = JSON.parse(raw);
    37→    return Array.isArray(parsed) ? parsed : [];
    38→  } catch {
    39→    return [];
    40→  }
    41→}
    42→
    43→function writeJsonArray(fileName, arr) {
    44→  ensureDataDir();
    45→  const p = path.join(DATA_DIR, fileName);
    46→  fs.writeFileSync(p, JSON.stringify(arr, null, 2), 'utf8');
    47→}
