    98→function adoBaseUrl(org, project) {
    99→  return `https://dev.azure.com/${encodeURIComponent(org)}/${encodeURIComponent(project)}/_apis`;
   100→}
   101→
   102→function adoHeaders(pat) {
   103→  const auth = Buffer.from(`:${pat}`).toString('base64');
   104→  return {
   105→    Authorization: `Basic ${auth}`,
   106→    Accept: 'application/json',
   107→    // KEY: avoid redirecting to interactive AAD sign-in (HTML)
   108→    'X-TFS-FedAuthRedirect': 'Suppress',
   109→    // Optional but helpful
   110→    'User-Agent': 'DevOpsDashboard/1.0'
   111→  };
   112→}
   113→
   114→async function readTextSafe(resp) {
   115→  try { return await resp.text(); } catch { return ''; }
   116→}
   117→
   118→function isLikelyHtml(ct, body) {
   119→  const c = (ct || '').toLowerCase();
   120→  const b = (body || '').trim().toLowerCase();
   121→  return c.includes('text/html') || b.startsWith('<!doctype html') || b.startsWith('<html');
   122→}
