   124→// POST /api/azuredevops/sync
   125→app.post('/api/azuredevops/sync', async (req, res) => {
   126→  try {
   127→    let {
   128→      organization,
   129→      project,
   130→      personalAccessToken,
   131→      apiVersion = '7.0'
   132→    } = req.body || {};
   133→
   134→    organization = normalizeOrgInput(organization);
   135→    project = String(project || '').trim();
   136→    personalAccessToken = String(personalAccessToken || '').trim();
   137→    apiVersion = String(apiVersion || '7.0').trim() || '7.0';
   138→
   139→    console.log("==== ADO SYNC DEBUG START ====");
   140→
   141→    console.log("Raw body:", {
   142→      organization: req.body?.organization,
   143→      project: req.body?.project,
   144→      apiVersion: req.body?.apiVersion,
   145→      patLength: req.body?.personalAccessToken?.length || 0
   146→    });
   147→
   148→    if (!organization || !project || !personalAccessToken) {
   149→      return res.status(400).json({
   150→        error: 'Missing organization, project, or personalAccessToken',
   151→        organization,
   152→        projectPresent: !!project,
   153→        patPresent: !!personalAccessToken
   154→      });
   155→    }
   156→
   157→    const baseUrl = adoBaseUrl(organization, project);
   158→
   159→    // WIQL: IDs only
   160→    const wiqlQuery = {
   161→      query: `
   162→SELECT [System.Id]
   163→FROM workitems
   164→WHERE [System.TeamProject] = '${project.replace(/'/g, "''")}'
   165→  AND [System.State] <> 'Removed'
   166→ORDER BY [System.ChangedDate] DESC`
   167→    };
   168→
   169→    const wiqlUrl = `${baseUrl}/wit/wiql?api-version=${apiVersion}`;
   170→
   171→    const wiqlResp = await fetch(wiqlUrl, {
   172→      method: 'POST',
   173→      redirect: 'manual', // KEY: don't follow redirects to sign-in pages
   174→      headers: { ...adoHeaders(personalAccessToken), 'Content-Type': 'application/json' },
   175→      body: JSON.stringify(wiqlQuery)
   176→    });
   177→
   178→    const wiqlCT = wiqlResp.headers.get('content-type') || '';
   179→    const wiqlText = await readTextSafe(wiqlResp);
   180→
   181→    // If redirected (302/303) you’ll see it here
   182→    if (wiqlResp.status >= 300 && wiqlResp.status < 400) {
   183→      return res.status(502).json({
   184→        error: 'Azure DevOps returned a redirect (likely to interactive sign-in).',
   185→        status: wiqlResp.status,
   186→        location: wiqlResp.headers.get('location'),
   187→        urlCalled: wiqlUrl
   188→      });
   189→    }
   190→
   191→    if (!wiqlResp.ok) {
   192→      return res.status(wiqlResp.status).json({
   193→        error: 'WIQL failed',
   194→        status: wiqlResp.status,
   195→        contentType: wiqlCT,
   196→        bodyPreview: wiqlText.substring(0, 700),
   197→        urlCalled: wiqlUrl
   198→      });
   199→    }
   200→
   201→    if (!wiqlCT.includes('application/json') || isLikelyHtml(wiqlCT, wiqlText)) {
   202→      return res.status(502).json({
   203→        error: 'Azure DevOps returned non-JSON for WIQL (sign-in HTML or auth policy).',
   204→        status: wiqlResp.status,
   205→        contentType: wiqlCT,
   206→        bodyPreview: wiqlText.substring(0, 700),
   207→        urlCalled: wiqlUrl,
   208→        org: organization,
   209→        project
   210→      });
   211→    }
   212→
   213→    const wiqlResult = JSON.parse(wiqlText);
   214→    const ids = (wiqlResult.workItems || []).map(w => w.id);
   215→
   216→    if (!ids.length) return res.json({ items: [] });
   217→
   218→    // Fetch details in chunks
   219→    const batchSize = 200;
   220→    const all = [];
   221→
   222→    for (let i = 0; i < ids.length; i += batchSize) {
   223→      const batchIds = ids.slice(i, i + batchSize).join(',');
   224→      const detUrl = `${baseUrl}/wit/workitems?ids=${batchIds}&$expand=all&api-version=${apiVersion}`;
   225→
   226→      const detResp = await fetch(detUrl, {
   227→        method: 'GET',
   228→        redirect: 'manual',
   229→        headers: adoHeaders(personalAccessToken)
   230→      });
   231→
   232→      const detCT = detResp.headers.get('content-type') || '';
   233→      const detText = await readTextSafe(detResp);
   234→
   235→      if (detResp.status >= 300 && detResp.status < 400) {
   236→        return res.status(502).json({
   237→          error: 'Azure DevOps details request redirected (likely to sign-in).',
   238→          status: detResp.status,
   239→          location: detResp.headers.get('location'),
   240→          urlCalled: detUrl
   241→        });
   242→      }
   243→
   244→      if (!detResp.ok) {
   245→        return res.status(detResp.status).json({
   246→          error: 'Details fetch failed',
   247→          status: detResp.status,
   248→          contentType: detCT,
   249→          bodyPreview: detText.substring(0, 700),
   250→          urlCalled: detUrl
   251→        });
   252→      }
   253→
   254→      if (!detCT.includes('application/json') || isLikelyHtml(detCT, detText)) {
   255→        return res.status(502).json({
   256→          error: 'Azure DevOps returned non-JSON for details (sign-in HTML or auth policy).',
   257→          status: detResp.status,
   258→          contentType: detCT,
   259→          bodyPreview: detText.substring(0, 700),
   260→          urlCalled: detUrl
   261→        });
   262→      }
   263→
   264→      const det = JSON.parse(detText);
   265→      all.push(...(det.value || []));
   266→    }
   267→
   268→    return res.json({ items: all });
   269→  } catch (err) {
   270→    return res.status(500).json({ error: err.message || String(err) });
   271→  }
   272→});
