   335→app.post('/api/azuredevops/create', async (req, res) => {
   336→  try {
   337→    const { organization, project, personalAccessToken, apiVersion = '7.0', workItem } = req.body || {};
   338→    if (!organization || !project || !personalAccessToken) {
   339→      return res.status(400).json({ error: 'Missing organization/project/personalAccessToken' });
   340→    }
   341→    if (!workItem?.title) {
   342→      return res.status(400).json({ error: 'Missing workItem.title' });
   343→    }
   344→
   345→    const type = encodeURIComponent(workItem.workItemType || 'Task');
   346→
   347→    const createUrl =
   348→      `https://dev.azure.com/${encodeURIComponent(organization)}/${encodeURIComponent(project)}` +
   349→      `/_apis/wit/workitems/$${type}?api-version=${encodeURIComponent(apiVersion)}`;
   350→
   351→    // Enforce required tags so it shows up in your dashboard
   352→    const tags = ensureAllowedTags(workItem.tags);
   353→
   354→    // JSON Patch document
   355→    const patch = [
   356→      { op: 'add', path: '/fields/System.Title', value: String(workItem.title) },
   357→      { op: 'add', path: '/fields/System.Tags', value: tags }
   358→    ];
   359→
   360→    if (workItem.description) {
   361→      patch.push({ op: 'add', path: '/fields/System.Description', value: String(workItem.description) });
   362→    }
   363→    if (workItem.areaPath) {
   364→      patch.push({ op: 'add', path: '/fields/System.AreaPath', value: String(workItem.areaPath) });
   365→    }
   366→    if (workItem.priority) {
   367→      patch.push({ op: 'add', path: '/fields/Microsoft.VSTS.Common.Priority', value: Number(workItem.priority) });
   368→    }
   369→
   370→    const resp = await fetch(createUrl, {
   371→      method: 'POST',
   372→      headers: {
   373→        ...adoHeaders(personalAccessToken),
   374→        'Content-Type': 'application/json-patch+json',
   375→        Accept: 'application/json'
   376→      },
   377→      body: JSON.stringify(patch)
   378→    });
   379→
   380→    const json = await resp.json().catch(() => ({}));
   381→    if (!resp.ok) {
   382→      return res.status(resp.status).json({
   383→        error: 'Create failed',
   384→        bodyPreview: JSON.stringify(json).slice(0, 500)
   385→      });
   386→    }
   387→
   388→    return res.json(json);
   389→  } catch (e) {
   390→    return res.status(500).json({ error: e.message || 'Create failed' });
   391→  }
   392→});
